    fold: { title: "Conversor de fold change", intro: "Usa el log2 ratio para interpretar up/down regulation.", label: "log2 ratio", fc: "Fold change", interpretation: "Interpretación" },
    pAlpha: { title: "Lab p-value vs alpha", intro: "Elige alpha y p-value, y lee la decisión.", alpha: "corte alpha", p: "p-value", reject: "p ≤ alpha: rechazar H0", retain: "p > alpha: no rechazar H0", pNotAlpha: "Recuerda: p se calcula con los datos; alpha se elige antes del test." },
    power: { title: "Explorador de power", intro: "Cambia un factor del diseño y observa el efecto cualitativo en power.", factor: "Factor de diseño", factors: { effect: "Mayor effect size", sample: "Mayor sample size", variability: "Mayor variabilidad", alphaStrict: "Alpha más estricto, ej. 0.01" }, messages: { effect: "Power aumenta: efectos grandes son más fáciles de detectar.", sample: "Power aumenta: más datos reducen incertidumbre.", variability: "Power disminuye: el ruido oculta efectos reales.", alphaStrict: "Disminuye Type I error, pero puede aumentar Type II si no hay suficiente n/efecto." } },
    normality: { title: "Checkpoint de normalidad", intro: "Selecciona el resultado de Shapiro–Wilk.", normal: "p > 0.05", notNormal: "p ≤ 0.05", normalMsg: "No se rechaza normalidad: se puede considerar un test paramétrico.", notNormalMsg: "Se rechaza normalidad: considera test no paramétrico o transformación." },
    selector: { title: "Selector de test para dos grupos", intro: "Selecciona dependencia y distribución para ver el test recomendado.", dependence: "Relación", distribution: "Distribución", paired: "paired/dependiente", unpaired: "unpaired/independiente", parametric: "paramétrica/normal", nonparametric: "no paramétrica", result: "Test recomendado" },
    welch: { title: "Mini-decisión de Welch", intro: "Grupos independientes, pero ¿hay que corregir?", options: ["27 vs 11 pacientes, varianza distinta", "50 vs 52 pacientes, varianza similar", "mismos pacientes before/after"], answers: ["Welch unpaired t-test si aún es paramétrico", "unpaired Student t-test", "test paired, no Welch"] },
    wilcoxon: { title: "Lab Wilcoxon signed-rank", intro: "Diferencias: −15, −7, +5, +20, 0, −9, +17, −12, +5, −10. El cero se excluye; empates promedian rangos.", positive: "Suma de rangos positivos", negative: "Suma de rangos negativos", decision: "Como W = min(20,25) = 20 y W crítico = 5, no se rechaza H0 en el ejemplo toy." },
    mann: { title: "Lab Mann–Whitney rank-sum", intro: "Para grupos independientes, combina todos los valores y ordénalos por rango. Luego compara el U menor con el valor crítico.", sampleA: "Sample A", sampleB: "Sample B", result: "En el ejemplo de la slide, U1 = 35 y U2 = 1, así que U = 1. Como 1 < 5, se rechaza H0." },
    quiz: COPY.en.tools.quiz
