function clamp01(x) { return Math.max(0, Math.min(1, x)); }
function logGamma(z) { const p = [676.5203681218851, -1259.1392167224028, 771.32342877765313, -176.61502916214059, 12.507343278686905, -0.13857109526572012, 9.9843695780195716e-6, 1.5056327351493116e-7]; if (z < 0.5) return Math.log(Math.PI) - Math.log(Math.sin(Math.PI * z)) - logGamma(1 - z); z -= 1; let x = 0.99999999999980993; for (let i = 0; i < p.length; i += 1) x += p[i] / (z + i + 1); const t = z + p.length - 0.5; return 0.5 * Math.log(2 * Math.PI) + (z + 0.5) * Math.log(t) - t + Math.log(x); }
function betaContinuedFraction(x, a, b) { const MAXIT = 100, EPS = 3e-7, FPMIN = 1e-30; let qab = a + b, qap = a + 1, qam = a - 1; let c = 1, d = 1 - qab * x / qap; if (Math.abs(d) < FPMIN) d = FPMIN; d = 1 / d; let h = d; for (let m = 1; m <= MAXIT; m += 1) { const m2 = 2 * m; let aa = m * (b - m) * x / ((qam + m2) * (a + m2)); d = 1 + aa * d; if (Math.abs(d) < FPMIN) d = FPMIN; c = 1 + aa / c; if (Math.abs(c) < FPMIN) c = FPMIN; d = 1 / d; h *= d * c; aa = -(a + m) * (qab + m) * x / ((a + m2) * (qap + m2)); d = 1 + aa * d; if (Math.abs(d) < FPMIN) d = FPMIN; c = 1 + aa / c; if (Math.abs(c) < FPMIN) c = FPMIN; d = 1 / d; const del = d * c; h *= del; if (Math.abs(del - 1) < EPS) break; } return h; }
function regularizedBeta(x, a, b) { if (x <= 0) return 0; if (x >= 1) return 1; const bt = Math.exp(logGamma(a + b) - logGamma(a) - logGamma(b) + a * Math.log(x) + b * Math.log(1 - x)); return x < (a + 1) / (a + b + 2) ? bt * betaContinuedFraction(x, a, b) / a : 1 - bt * betaContinuedFraction(1 - x, b, a) / b; }
function studentTwoTailP(t, df) { if (!Number.isFinite(t) || !Number.isFinite(df) || df <= 0) return NaN; const x = df / (df + t * t); return clamp01(regularizedBeta(x, df / 2, 0.5)); }
function wilcoxonApproxP(stats) { if (!stats || stats.n < 2 || !Number.isFinite(stats.w)) return NaN; const n = stats.n; const meanW = n * (n + 1) / 4; const sdW = Math.sqrt(n * (n + 1) * (2 * n + 1) / 24); const z = (stats.w - meanW + 0.5) / sdW; return clamp01(2 * normalCdf(z)); }
function mannApproxP(stats) { if (!stats || stats.n1 < 2 || stats.n2 < 2 || !Number.isFinite(stats.u)) return NaN; const meanU = stats.n1 * stats.n2 / 2; const sdU = Math.sqrt(stats.n1 * stats.n2 * (stats.n1 + stats.n2 + 1) / 12); const z = (stats.u - meanU + 0.5) / sdU; const tail = Math.min(normalCdf(z), 1 - normalCdf(z)); return clamp01(2 * tail); }
function normalQuantile(p) { if (p <= 0 || p >= 1) return NaN; const a = [-39.69683028665376, 220.9460984245205, -275.9285104469687, 138.357751867269, -30.66479806614716, 2.506628277459239]; const b = [-54.47609879822406, 161.5858368580409, -155.6989798598866, 66.80131188771972, -13.28068155288572]; const c = [-0.007784894002430293, -0.3223964580411365, -2.400758277161838, -2.549732539343734, 4.374664141464968, 2.938163982698783]; const d = [0.007784695709041462, 0.3224671290700398, 2.445134137142996, 3.754408661907416]; const plow = 0.02425, phigh = 1 - plow; let q, r; if (p < plow) { q = Math.sqrt(-2 * Math.log(p)); return (((((c[0] * q + c[1]) * q + c[2]) * q + c[3]) * q + c[4]) * q + c[5]) / ((((d[0] * q + d[1]) * q + d[2]) * q + d[3]) * q + 1); } if (phigh < p) { q = Math.sqrt(-2 * Math.log(1 - p)); return -(((((c[0] * q + c[1]) * q + c[2]) * q + c[3]) * q + c[4]) * q + c[5]) / ((((d[0] * q + d[1]) * q + d[2]) * q + d[3]) * q + 1); } q = p - 0.5; r = q * q; return (((((a[0] * r + a[1]) * r + a[2]) * r + a[3]) * r + a[4]) * r + a[5]) * q / (((((b[0] * r + b[1]) * r + b[2]) * r + b[3]) * r + b[4]) * r + 1); }
function shapiroHeuristic(values) { const xs = [...values].sort((a, b) => a - b); const n = xs.length; if (n < 3) return { n, sorted: xs, expected: [], wLike: NaN }; const m = mean(xs), s = sd(xs); const expected = xs.map((_, i) => m + s * normalQuantile((i + 0.375) / (n + 0.25))); const centeredX = xs.map((x) => x - mean(xs)); const centeredE = expected.map((x) => x - mean(expected)); const num = centeredX.reduce((sum, x, i) => sum + x * centeredE[i], 0); const den = Math.sqrt(centeredX.reduce((sum, x) => sum + x * x, 0) * centeredE.reduce((sum, x) => sum + x * x, 0)); return { n, sorted: xs, expected, wLike: den ? (num / den) ** 2 : NaN }; }

function DataBox({ label, value, onChange }) { return <label className="block"><span className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{label}</span><textarea value={value} onChange={(e) => onChange(e.target.value)} className="mt-2 min-h-[90px] w-full rounded-2xl border border-stone-200 bg-white p-3 text-sm font-bold leading-6 text-stone-800 outline-none focus:border-red-300" /></label>; }
function ResultPill({ label, value, tone = "stone" }) { return <div className={`rounded-2xl border p-4 ${tone === "red" ? "border-red-200 bg-red-50" : "border-stone-200 bg-white"}`}><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{label}</div><div className="mt-1 text-2xl font-black text-stone-950">{value}</div></div>; }
function StepsPanel({ t, steps }) { return <div className="rounded-[1.5rem] border border-stone-200 bg-white p-5"><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{t.steps}</div><ol className="mt-3 space-y-2 text-sm font-semibold leading-6 text-stone-700">{steps.map((step, i) => <li key={step} className="flex gap-3"><span className="flex h-6 w-6 shrink-0 items-center justify-center rounded-full bg-red-700 text-xs font-black text-white">{i + 1}</span><span>{step}</span></li>)}</ol><p className="mt-4 rounded-2xl bg-amber-50 p-3 text-xs font-black leading-5 text-amber-900">{t.warning}</p></div>; }
function InlineArray({ label, values }) { return <div className="rounded-2xl bg-stone-50 p-3"><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{label}</div><p className="mt-1 break-words text-sm font-bold leading-6 text-stone-700">{values.length ? values.map((x) => fmt(x, 2)).join(", ") : "—"}</p></div>; }
function NormalityLab({ tools, lang = "es" }) { const d = decisionText(lang); const defaults = "-0.45, -0.38, -0.31, -0.22, -0.10, -0.04, 0.08, 0.14, 0.25, 0.39, 0.51"; const [raw, setRaw] = useState(defaults); const [pRaw, setPRaw] = useState("0.18"); const values = parseNumbers(raw); const pValue = Number(pRaw); const stats = shapiroHeuristic(values); const valid = values.length >= 3 && Number.isFinite(stats.wLike); return <InteractiveShell title={d.shapiroTitle || tools.title} intro={d.shapiroIntro || tools.intro}><DataBox label={lang === "en" ? "Sample values" : lang === "fa" ? "مقادیر نمونه" : "Valores muestrales"} value={raw} onChange={setRaw}/><div className="mt-3 flex flex-wrap items-end gap-3"><button onClick={() => { setRaw(defaults); setPRaw("0.18"); }} className="rounded-full border border-stone-200 bg-white px-4 py-2 text-xs font-black text-stone-700">{labText(lang).reset}</button><label className="min-w-[220px] text-xs font-black uppercase tracking-[0.18em] text-stone-500">{d.softwareP}<input type="number" step="0.0001" min="0" max="1" value={pRaw} onChange={(e) => setPRaw(e.target.value)} className="mt-2 w-full rounded-2xl border border-stone-200 bg-white px-4 py-3 text-sm font-bold normal-case tracking-normal text-stone-800"/></label></div>{!valid ? <p className="mt-4 rounded-2xl border border-red-200 bg-red-50 p-4 text-sm font-black text-red-800">{lang === "en" ? "Add at least three numeric values for a normality check." : lang === "fa" ? "برای بررسی normality حداقل سه مقدار عددی وارد کنید." : "Añade al menos tres valores numéricos para revisar normalidad."}</p> : <><div className="mt-4 grid gap-3 md:grid-cols-4"><ResultPill label={labText(lang).n} value={stats.n}/><ResultPill label={labText(lang).mean} value={fmt(mean(values))} tone="red"/><ResultPill label={labText(lang).sd} value={fmt(sd(values))}/><ResultPill label={d.wLike} value={fmt(stats.wLike, 4)} tone="red"/></div><div className="mt-4 grid gap-4 lg:grid-cols-[1fr_0.9fr]"><div className="space-y-3"><InlineArray label={lang === "en" ? "Sorted values" : lang === "fa" ? "مقادیر مرتب‌شده" : "Valores ordenados"} values={stats.sorted}/><InlineArray label={d.expectedNormal} values={stats.expected}/><p className="rounded-2xl bg-amber-50 p-3 text-xs font-black leading-5 text-amber-900">{d.shapiroNote}</p></div><StepsPanel t={labText(lang)} steps={lang === "en" ? ["Order the sample values from low to high.", "Compare the ordered values with the quantiles expected under a normal distribution.", "Run Shapiro–Wilk in software to obtain W and the exact p-value.", "H0 says the sample is compatible with normality.", "Compare the p-value with alpha: p ≤ alpha rejects normality; p > alpha does not reject normality."] : lang === "fa" ? ["مقادیر نمونه را از کم به زیاد مرتب کنید.", "مقادیر مرتب‌شده را با quantileهای مورد انتظار در توزیع نرمال مقایسه کنید.", "برای W و p-value دقیق، Shapiro–Wilk را در نرم‌افزار اجرا کنید.", "H0 می‌گوید نمونه با normality سازگار است.", "p-value را با alpha مقایسه کنید: p ≤ alpha یعنی normality رد می‌شود؛ p > alpha یعنی رد نمی‌شود."] : ["Ordena los valores muestrales de menor a mayor.", "Compara los valores ordenados con los cuantiles esperados bajo una distribución normal.", "Ejecuta Shapiro–Wilk en software para obtener W y el p-value exacto.", "H0 dice que la muestra es compatible con normalidad.", "Compara el p-value con alpha: p ≤ alpha rechaza normalidad; p > alpha no rechaza normalidad."]}/></div><DecisionPanel lang={lang} h0Key="shapiro" pValue={pValue} mode="shapiro" label={d.softwareP}/></>}</InteractiveShell>; }
function PairedTDataLab({ lang = "es" }) { const t = labText(lang); const defaults = { before: "7.2, 5.9, 6.4, 8.1, 7.7, 6.9", after: "6.6, 5.1, 6.0, 7.5, 7.0, 6.5" }; const [beforeRaw, setBeforeRaw] = useState(defaults.before); const [afterRaw, setAfterRaw] = useState(defaults.after); const before = parseNumbers(beforeRaw); const after = parseNumbers(afterRaw); const lengthMismatch = before.length !== after.length; const stats = pairedStats(before, after); const valid = !lengthMismatch && stats.n >= 2 && Number.isFinite(stats.t); const pValue = valid ? studentTwoTailP(stats.t, stats.df) : NaN; const sign = !valid ? "" : stats.meanDiff < -0.001 ? t.signDown : stats.meanDiff > 0.001 ? t.signUp : t.signNeutral; return <InteractiveShell title={t.pairedTitle} intro={t.pairedIntro}><div className="grid gap-4 md:grid-cols-2"><DataBox label={t.before} value={beforeRaw} onChange={setBeforeRaw}/><DataBox label={t.after} value={afterRaw} onChange={setAfterRaw}/></div><button onClick={() => { setBeforeRaw(defaults.before); setAfterRaw(defaults.after); }} className="mt-3 rounded-full border border-stone-200 bg-white px-4 py-2 text-xs font-black text-stone-700">{t.reset}</button>{lengthMismatch ? <p className="mt-4 rounded-2xl border border-amber-200 bg-amber-50 p-4 text-sm font-black text-amber-900">{lengthMismatchMessage(lang, before.length, after.length)}</p> : null}{!valid ? <p className="mt-4 rounded-2xl border border-red-200 bg-red-50 p-4 text-sm font-black text-red-800">{t.pairedInvalid}</p> : <><div className="mt-4 grid gap-3 md:grid-cols-5"><ResultPill label={t.n} value={stats.n}/><ResultPill label="mean diff" value={fmt(stats.meanDiff)} tone="red"/><ResultPill label={t.sd} value={fmt(stats.sdDiff)}/><ResultPill label={t.t} value={fmt(stats.t)} tone="red"/><ResultPill label={t.df} value={fmt(stats.df, 0)}/></div><DecisionPanel lang={lang} h0Key="pairedT" pValue={pValue} approximate={false}/><div className="mt-4 grid gap-4 lg:grid-cols-[1fr_0.9fr]"><div className="space-y-3"><InlineArray label={t.diffs} values={stats.diffs}/><p className="rounded-2xl bg-stone-950 p-4 text-sm font-black leading-6 text-white">{sign}</p></div><StepsPanel t={t} steps={t.pairedSteps}/></div></>}</InteractiveShell>; }
function TestSelector({ tools, lang = "es" }) { const [dep, setDep] = useState("paired"); const [dist, setDist] = useState("parametric"); let result = ""; if (dep === "paired" && dist === "parametric") result = "Paired Student t-test"; if (dep === "paired" && dist === "nonparametric") result = "Wilcoxon signed-rank test"; if (dep === "unpaired" && dist === "parametric") result = "Unpaired Student t-test; Welch if variance/sample size differs"; if (dep === "unpaired" && dist === "nonparametric") result = "Mann–Whitney U / Wilcoxon rank-sum"; return <><InteractiveShell title={tools.title} intro={tools.intro}><div className="grid gap-4 md:grid-cols-2"><div><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{tools.dependence}</div><div className="mt-2 flex gap-2"><button onClick={() => setDep("paired")} className={`rounded-full px-4 py-2 text-sm font-black ${dep === "paired" ? "bg-red-700 text-white" : "border border-stone-200 bg-white"}`}>{tools.paired}</button><button onClick={() => setDep("unpaired")} className={`rounded-full px-4 py-2 text-sm font-black ${dep === "unpaired" ? "bg-red-700 text-white" : "border border-stone-200 bg-white"}`}>{tools.unpaired}</button></div></div><div><div className="text-xs font-black uppercase tracking-[0.18em] text-stone-500">{tools.distribution}</div><div className="mt-2 flex gap-2"><button onClick={() => setDist("parametric")} className={`rounded-full px-4 py-2 text-sm font-black ${dist === "parametric" ? "bg-red-700 text-white" : "border border-stone-200 bg-white"}`}>{tools.parametric}</button><button onClick={() => setDist("nonparametric")} className={`rounded-full px-4 py-2 text-sm font-black ${dist === "nonparametric" ? "bg-red-700 text-white" : "border border-stone-200 bg-white"}`}>{tools.nonparametric}</button></div></div></div><div className="mt-4 rounded-2xl bg-stone-950 p-5 text-white"><div className="text-xs font-black uppercase tracking-[0.18em] text-red-200">{tools.result}</div><div className="mt-2 text-2xl font-black">{result}</div></div></InteractiveShell><PairedTDataLab lang={lang}/></>; }
function WelchMini({ tools, lang = "es" }) { const t = labText(lang); const defaults = { a: "7.22, 5.25, 6.58, 6.19, 3.00, 5.61, 7.21, 6.81", b: "6.78, 4.95, 6.52, 4.81, 6.19" }; const [aRaw, setARaw] = useState(defaults.a); const [bRaw, setBRaw] = useState(defaults.b); const a = parseNumbers(aRaw); const b = parseNumbers(bRaw); const stats = welchStats(a, b); const valid = a.length >= 2 && b.length >= 2 && Number.isFinite(stats.t); const pValue = valid ? studentTwoTailP(stats.t, stats.df) : NaN; return <InteractiveShell title={t.welchTitle} intro={t.welchIntro}><div className="grid gap-4 md:grid-cols-2"><DataBox label={t.groupA} value={aRaw} onChange={setARaw}/><DataBox label={t.groupB} value={bRaw} onChange={setBRaw}/></div><button onClick={() => { setARaw(defaults.a); setBRaw(defaults.b); }} className="mt-3 rounded-full border border-stone-200 bg-white px-4 py-2 text-xs font-black text-stone-700">{t.reset}</button>{!valid ? <p className="mt-4 rounded-2xl border border-red-200 bg-red-50 p-4 text-sm font-black text-red-800">{t.invalid}</p> : <><div className="mt-4 grid gap-3 md:grid-cols-4"><ResultPill label={`${t.n} A/B`} value={`${stats.n1}/${stats.n2}`}/><ResultPill label={`${t.mean} A`} value={fmt(stats.m1)} tone="red"/><ResultPill label={`${t.mean} B`} value={fmt(stats.m2)} tone="red"/><ResultPill label={t.t} value={fmt(stats.t)}/><ResultPill label={`${t.variance} A`} value={fmt(stats.v1)}/><ResultPill label={`${t.variance} B`} value={fmt(stats.v2)}/><ResultPill label={t.se} value={fmt(stats.se)}/><ResultPill label="Welch df" value={fmt(stats.df)}/></div><DecisionPanel lang={lang} h0Key="welch" pValue={pValue} approximate={false}/><div className="mt-4 grid gap-4 lg:grid-cols-[1fr_0.9fr]"><p className="rounded-2xl bg-stone-950 p-4 text-sm font-black leading-6 text-white">{stats.m1 > stats.m2 ? "Group A mean is higher in this toy dataset." : "Group B mean is higher in this toy dataset."}</p><StepsPanel t={t} steps={t.welchSteps}/></div></>}</InteractiveShell>; }
function WilcoxonLab({ tools, lang = "es" }) { const t = labText(lang); const defaults = { before: "100, 100, 100, 100, 100, 100, 100, 100, 100, 100", after: "85, 93, 105, 120, 100, 91, 117, 88, 105, 90" }; const [beforeRaw, setBeforeRaw] = useState(defaults.before); const [afterRaw, setAfterRaw] = useState(defaults.after); const before = parseNumbers(beforeRaw); const after = parseNumbers(afterRaw); const lengthMismatch = before.length !== after.length; const stats = wilcoxonStats(before, after); const valid = !lengthMismatch && stats.n >= 2 && Number.isFinite(stats.w); const pValue = valid ? wilcoxonApproxP(stats) : NaN; return <InteractiveShell title={t.wilcoxonTitle} intro={t.wilcoxonIntro}><div className="grid gap-4 md:grid-cols-2"><DataBox label={t.before} value={beforeRaw} onChange={setBeforeRaw}/><DataBox label={t.after} value={afterRaw} onChange={setAfterRaw}/></div><button onClick={() => { setBeforeRaw(defaults.before); setAfterRaw(defaults.after); }} className="mt-3 rounded-full border border-stone-200 bg-white px-4 py-2 text-xs font-black text-stone-700">{t.reset}</button>{lengthMismatch ? <p className="mt-4 rounded-2xl border border-amber-200 bg-amber-50 p-4 text-sm font-black text-amber-900">{lengthMismatchMessage(lang, before.length, after.length)}</p> : null}{!valid ? <p className="mt-4 rounded-2xl border border-red-200 bg-red-50 p-4 text-sm font-black text-red-800">{t.wilcoxonInvalid}</p> : <><div className="mt-4 grid gap-3 md:grid-cols-4"><ResultPill label={t.diffs} value={stats.diffs.length}/><ResultPill label="W+" value={fmt(stats.wPlus)} tone="red"/><ResultPill label="W−" value={fmt(stats.wMinus)} tone="red"/><ResultPill label="W = min" value={fmt(stats.w)}/></div><DecisionPanel lang={lang} h0Key="wilcoxon" pValue={pValue} approximate={true}/><div className="mt-4 grid gap-4 lg:grid-cols-[1fr_0.9fr]"><div className="space-y-3"><InlineArray label={t.diffs} values={stats.raw}/><InlineArray label={t.ranks} values={stats.ranks}/><InlineArray label="signed ranks" values={stats.signed}/></div><StepsPanel t={t} steps={t.wilcoxonSteps}/></div></>}</InteractiveShell>; }
function MannLab({ tools, lang = "es" }) { const t = labText(lang); const defaults = { a: "25, 25, 19, 21, 22, 19", b: "18, 14, 13, 15, 17, 19" }; const [aRaw, setARaw] = useState(defaults.a); const [bRaw, setBRaw] = useState(defaults.b); const a = parseNumbers(aRaw); const b = parseNumbers(bRaw); const stats = mannStats(a, b); const valid = a.length >= 2 && b.length >= 2 && Number.isFinite(stats.u); const pValue = valid ? mannApproxP(stats) : NaN; return <InteractiveShell title={t.mannTitle} intro={t.mannIntro}><div className="grid gap-4 md:grid-cols-2"><DataBox label={tools.sampleA || t.groupA} value={aRaw} onChange={setARaw}/><DataBox label={tools.sampleB || t.groupB} value={bRaw} onChange={setBRaw}/></div><button onClick={() => { setARaw(defaults.a); setBRaw(defaults.b); }} className="mt-3 rounded-full border border-stone-200 bg-white px-4 py-2 text-xs font-black text-stone-700">{t.reset}</button>{!valid ? <p className="mt-4 rounded-2xl border border-red-200 bg-red-50 p-4 text-sm font-black text-red-800">{t.invalid}</p> : <><div className="mt-4 grid gap-3 md:grid-cols-5"><ResultPill label={`${t.n} A/B`} value={`${stats.n1}/${stats.n2}`}/><ResultPill label={`${t.rankSum} A`} value={fmt(stats.rA)} tone="red"/><ResultPill label={`${t.rankSum} B`} value={fmt(stats.rB)} tone="red"/><ResultPill label="U1 / U2" value={`${fmt(stats.uA)}/${fmt(stats.uB)}`}/><ResultPill label="U = min" value={fmt(stats.u)}/></div><DecisionPanel lang={lang} h0Key="mann" pValue={pValue} approximate={true}/><div className="mt-4 grid gap-4 lg:grid-cols-[1fr_0.9fr]"><div className="max-h-[260px] overflow-auto rounded-2xl border border-stone-200 bg-white p-3"><div className="grid grid-cols-3 gap-2 text-xs font-black uppercase tracking-[0.12em] text-stone-500"><span>value</span><span>group</span><span>rank</span></div>{stats.ranked.map((row, i) => <div key={`${row.value}-${row.group}-${i}`} className="mt-2 grid grid-cols-3 gap-2 rounded-xl bg-stone-50 p-2 text-sm font-bold text-stone-700"><span>{fmt(row.value, 2)}</span><span>{row.group}</span><span>{fmt(row.rank, 2)}</span></div>)}</div><StepsPanel t={t} steps={t.mannSteps}/></div></>}</InteractiveShell>; }
function Quiz({ ui, copy }) { const [answers, setAnswers] = useState({}); const items = copy.tools.quiz.items; const score = items.reduce((acc, item, i) => acc + (answers[i] === item.answer ? 1 : 0), 0); return <section className="mt-10 rounded-[2rem] border border-stone-200 bg-white p-6 shadow-sm"><SectionHeader eyebrow={ui.checkpoint} title={copy.quizTitle}>Score: {score}/{items.length}</SectionHeader><div className="grid gap-4 md:grid-cols-2">{items.map((item, i) => <div key={item.q} className="rounded-2xl border border-stone-200 bg-stone-50 p-4"><p className="font-black text-stone-950">{i + 1}. {item.q}</p><div className="mt-3 grid gap-2">{item.options.map((option, j) => <button key={option} onClick={() => setAnswers({ ...answers, [i]: j })} className={`rounded-xl border px-3 py-2 text-left text-sm font-bold ${answers[i] === j ? (j === item.answer ? "border-emerald-300 bg-emerald-50 text-emerald-800" : "border-red-300 bg-red-50 text-red-800") : "border-stone-200 bg-white text-stone-700"}`}>{option}</button>)}</div></div>)}</div></section>; }
function WrittenTrainer({ ui, copy }) { const [text, setText] = useState(""); const wc = text.trim() ? text.trim().split(/\s+/).length : 0; return <section className="mt-10 rounded-[2rem] border border-stone-200 bg-white p-6 shadow-sm"><SectionHeader eyebrow={ui.exam} title={copy.writtenTitle}>{copy.writtenPrompt}</SectionHeader><textarea value={text} onChange={(e) => setText(e.target.value)} placeholder={copy.writtenPlaceholder} className="min-h-[220px] w-full rounded-[1.5rem] border border-stone-200 bg-stone-50 p-4 text-sm font-semibold leading-6 outline-none focus:border-red-300"/><div className="mt-2 text-xs font-black uppercase tracking-[0.18em] text-stone-500">{wc} {ui.words}</div><details className="mt-4 rounded-[1.5rem] border border-stone-200 bg-stone-50 p-4"><summary className="cursor-pointer font-black text-red-800">{ui.model}</summary><p className="mt-3 text-sm font-semibold leading-7 text-stone-700">{copy.writtenModel}</p></details></section>; }

function sectionExtra(name, tools, lang = "es") { const map = { designFlow: <DesignFlow tools={tools.designFlow}/>, foldLab: <FoldLab tools={tools.fold}/>, pAlpha: <PAlphaLab tools={tools.pAlpha} lang={lang}/>, powerLab: <PowerLab tools={tools.power}/>, normality: <NormalityLab tools={tools.normality} lang={lang}/>, testSelector: <TestSelector tools={tools.selector} lang={lang}/>, welchMini: <WelchMini tools={tools.welch} lang={lang}/>, wilcoxonLab: <WilcoxonLab tools={tools.wilcoxon} lang={lang}/>, mannLab: <MannLab tools={tools.mann} lang={lang}/> }; return map[name] || null; }

export default function DRDLesson06({ lang = "es", isDone = false, toggle = () => {} }) {
  const ui = getUi(lang);
  const copy = getCopy(lang);
  const [zoom, setZoom] = useState(null);
  const sections = useMemo(() => copy.sections, [copy]);
  return <main className="mx-auto w-[min(1180px,calc(100%-24px))] pb-16 pt-8 md:pt-12 text-stone-900"><Navigation ui={ui} isDone={isDone} toggle={toggle}/>
    <section className="overflow-hidden rounded-[2.5rem] border border-stone-200 bg-[#fffaf0]/92 shadow-xl shadow-stone-900/5"><div className="grid gap-0 lg:grid-cols-[1.05fr_0.95fr]"><div className="p-7 md:p-10 lg:p-12"><HeroEyebrow>{ui.heroEyebrow}</HeroEyebrow><h1 className="mt-5 max-w-4xl text-4xl font-black leading-[0.96] tracking-tight text-stone-950 md:text-6xl">{ui.heroTitle}</h1><p className="mt-6 max-w-3xl text-lg leading-8 text-stone-700">{ui.heroSubtitle}</p><div className="mt-6 flex flex-wrap gap-2">{ui.tags.map((tag) => <Pill key={tag} tone={tag.toLowerCase().includes("p-value") ? "red" : "stone"}>{tag}</Pill>)}</div></div><div className="border-t border-stone-200 bg-white/70 p-5 lg:border-l lg:border-t-0"><div className="h-full rounded-[2rem] border border-stone-200 bg-white p-5 shadow-inner"><div className="grid grid-cols-2 gap-3"><StatCard label={ui.module} value="1" tone="red"/><StatCard label={ui.writtenExam} value="4Q"/><StatCard label={ui.answerLines} value="10–12"/><StatCard label={ui.core} value="TEST" tone="red"/></div><div className="mt-5 rounded-3xl bg-stone-950 p-5 text-white"><div className="text-xs font-black uppercase tracking-[0.18em] text-red-200">{ui.bigIdea}</div><p className="mt-2 text-lg font-bold leading-7">{ui.bigIdeaText}</p></div><ResourceLinks ui={ui}/></div></div></div></section>
    {sections.map((section, idx) => <section key={section.title} className="mt-10 rounded-[2.5rem] border border-stone-200 bg-white/80 p-6 shadow-sm md:p-8"><SectionHeader eyebrow={`Part ${idx + 1}`} title={section.title}>{section.intro}</SectionHeader><SlideGrid ui={ui} slides={section.slides} openZoom={setZoom}/>{sectionExtra(section.extra, copy.tools, lang)}</section>)}
    <Quiz ui={ui} copy={copy}/><WrittenTrainer ui={ui} copy={copy}/><Navigation ui={ui} isDone={isDone} toggle={toggle} position="bottom"/><ZoomModal ui={ui} zoom={zoom} setZoom={setZoom}/>
  </main>;
}
